export function translate(locale: Locale, source: string): string { return locale === "en-US" ? english[source] ?? source : source; }
export function localeLabel(displayLocale: Locale, locale: Locale): string {
  if (displayLocale === "en-US") return locale === "zh-CN" ? "Simplified Chinese" : "English";
  return locale === "zh-CN" ? "简体中文" : "English";
}
export function loadLocale(): Locale {
  try { const value = localStorage.getItem(storageKey) ?? localStorage.getItem(legacyStorageKey); return supportedLocales.includes(value as Locale) ? value as Locale : "zh-CN"; }
  catch { return "zh-CN"; }
}
export function saveLocale(locale: Locale) { try { localStorage.setItem(storageKey, locale); } catch { /* storage can be disabled */ } }

function validTimeZone(value: string): boolean {
  if (!value) return false;
  try {
    new Intl.DateTimeFormat("en-US", { timeZone: value }).format();
    return true;
  } catch {
    return false;
  }
}

export function loadTimeZone(): string {
  try {
    const stored = localStorage.getItem(timeZoneStorageKey) ?? localStorage.getItem(legacyTimeZoneStorageKey) ?? "";
    if (validTimeZone(stored)) return stored;
  } catch { /* storage can be disabled */ }
  const detected = Intl.DateTimeFormat().resolvedOptions().timeZone;
  return validTimeZone(detected) ? detected : "UTC";
}

export function saveTimeZone(timeZone: string) {
  if (!validTimeZone(timeZone)) return;
  try { localStorage.setItem(timeZoneStorageKey, timeZone); } catch { /* storage can be disabled */ }
}

export function supportedTimeZones(): string[] {
  const values = (Intl as typeof Intl & { supportedValuesOf?: (key: "timeZone") => string[] }).supportedValuesOf?.("timeZone") ?? [];
  return [...new Set(["UTC", loadTimeZone(), ...values])].sort((a, b) => a.localeCompare(b));
}
